+	var startMsg *types.Issue
+	var err error
+
+	if daemonClient != nil {
+		resp, err := daemonClient.Show(&rpc.ShowArgs{ID: messageID})
+		if err != nil {
+			fmt.Fprintf(os.Stderr, "Error fetching message %s: %v\n", messageID, err)
